head.b:skin:
:root {
  /* TERMINAL COLOR PALETTE */
  --bg-color: #030303;
  --terminal-green: #00ff41;
  --terminal-dark: #003b00;
  --terminal-dim: rgba(0, 255, 65, 0.4);
  --terminal-glow: rgba(0, 255, 65, 0.2);
  --text-main: #00ff41;
  --text-muted: #008f11;
  --text-alert: #ff003c;
  --font-mono: 'Share Tech Mono', monospace;
  --border-style: 1px solid var(--terminal-green);
}

/* SYSTEM BREACH MODE (Replaces Light Mode) */
[data-theme="breach"] {
  --terminal-green: #ff003c;
  --terminal-dark: #3b0000;
  --terminal-dim: rgba(255, 0, 60, 0.4);
  --terminal-glow: rgba(255, 0, 60, 0.2);
  --text-main: #ff003c;
  --text-muted: #8f0022;
}

* { margin:0; padding:0; box-sizing:border-box; }
::selection { background: var(--terminal-green); color: #000; }
html { scroll-behavior: smooth; }
body {
  font-family: var(--font-mono);
  font-size: 1.1rem;
  background: var(--bg-color);
  color: var(--text-main);
  transition: color 0.1s;
  overflow-x: hidden;
}

h1, h2, h3, h4, h5, h6, a {
  font-family: var(--font-mono);
  color: var(--text-main);
  text-transform: uppercase;
}
a { text-decoration: none; }

/* ── CRT OVERLAY EFFECT ── */
.crt::before {
  content: " ";
  display: block;
  position: fixed; top: 0; left: 0; bottom: 0; right: 0;
  background: linear-gradient(rgba(18, 16, 16, 0) 50%, rgba(0, 0, 0, 0.25) 50%), linear-gradient(90deg, rgba(255, 0, 0, 0.06), rgba(0, 255, 0, 0.02), rgba(0, 0, 255, 0.06));
  z-index: 9998; background-size: 100% 2px, 3px 100%; pointer-events: none;
}
.crt::after {
  content: " ";
  display: block;
  position: fixed; top: 0; left: 0; bottom: 0; right: 0;
  background: radial-gradient(circle, rgba(0,0,0,0) 60%, rgba(0,0,0,0.6) 100%);
  z-index: 9999; pointer-events: none;
}

/* ── LIVE MATRIX BACKGROUND (Canvas Layer) ── */
#matrixCanvas {
  position: fixed; top: 0; left: 0; width: 100vw; height: 100vh;
  z-index: -2; background: #000;
}

/* ── GLITCH ANIMATIONS ── */
.glitch { position: relative; display: inline-block; }
.glitch:hover { animation: glitch-anim 0.2s linear infinite; text-shadow: 2px 0 var(--text-alert), -2px 0 blue; }
@keyframes glitch-anim {
  0% { transform: translate(0) }
  20% { transform: translate(-2px, 2px) }
  40% { transform: translate(-2px, -2px) }
  60% { transform: translate(2px, 2px) }
  80% { transform: translate(2px, -2px) }
  100% { transform: translate(0) }
}
.blink { animation: blinker 1s linear infinite; }
@keyframes blinker { 50% { opacity: 0; } }

/* ── SCROLL REVEAL ── */
.reveal { opacity: 0; transform: translateY(20px); transition: opacity 0.4s, transform 0.4s; }
.reveal.visible { opacity: 1; transform: translateY(0); }
.delay-1 { transition-delay: 0.1s; }
.delay-2 { transition-delay: 0.2s; }

/* ── INTRO SEQUENCE ── */
#intro-overlay {
  position: fixed; inset: 0; z-index: 10000; background: #000;
  display: flex; align-items: flex-start; justify-content: flex-start; padding: 2rem;
  animation: overlayOut 0.1s step-end 3s forwards;
}
.boot-sequence { color: var(--terminal-green); font-size: 1rem; line-height: 1.5; }
.boot-line { opacity: 0; margin-bottom: 5px; }
.boot-line:nth-child(1) { animation: showLine 0.1s forwards 0.2s; }
.boot-line:nth-child(2) { animation: showLine 0.1s forwards 0.6s; }
.boot-line:nth-child(3) { animation: showLine 0.1s forwards 1.2s; }
.boot-line:nth-child(4) { animation: showLine 0.1s forwards 1.5s; color: var(--text-alert); }
.boot-line:nth-child(5) { animation: showLine 0.1s forwards 2.0s; }
@keyframes showLine { to { opacity: 1; } }
@keyframes overlayOut { to { opacity: 0; pointer-events: none; display: none; } }

/* ── TERMINAL NAV ── */
nav { position: relative; z-index: 100; background: rgba(0,0,0,0.85); border-bottom: 2px dashed var(--terminal-dim); padding: 0.5rem 0; }
.nav-container { display: flex; align-items: center; justify-content: space-between; width: 100%; max-width: 1200px; padding: 0.5rem 2rem; margin: 0 auto; }
.nav-logo-section .widget { margin: 0; }
.nav-logo { font-size: 1.5rem; font-weight: bold; color: var(--terminal-green); }
.nav-logo::before { content: "root@"; color: var(--text-muted); }

.nav-right { display: flex; align-items: center; gap: 2rem; }
.nav-links-wrapper .widget { margin: 0; }
.nav-links { display: flex; gap: 2rem; list-style: none; align-items: center; margin: 0; padding: 0; }
.nav-links a { color: var(--text-muted); font-size: 1rem; font-weight: bold; transition: all 0.2s; }
.nav-links a:hover { color: var(--terminal-green); background: var(--terminal-dark); padding: 0 5px; }
.nav-links a::before { content: "[ "; color: var(--terminal-dim); opacity: 0; transition: opacity 0.2s; }
.nav-links a::after { content: " ]"; color: var(--terminal-dim); opacity: 0; transition: opacity 0.2s; }
.nav-links a:hover::before, .nav-links a:hover::after { opacity: 1; }

/* ── DROPDOWN ── */
.dropdown { position: relative; display: inline-block; }
.dropdown .dropbtn { cursor: pointer; display: flex; align-items: center; gap: 4px; }
.dropdown-content { display: none; position: absolute; background-color: #000; border: var(--border-style); min-width: 200px; top: 100%; left: 0; z-index: 101; padding: 0.5rem; }
.dropdown-content a { color: var(--terminal-green); padding: 0.5rem; display: block; font-size: 0.9rem; border-bottom: 1px dashed var(--terminal-dim); }
.dropdown-content a:hover { background-color: var(--terminal-dark); color: #fff; }
.dropdown:hover .dropdown-content { display: block; }

.hamburger { display: none; background: none; border: none; cursor: pointer; padding: 0.5rem; color: var(--terminal-green); font-family: var(--font-mono); font-size: 1.5rem; }

/* ── CLI SEARCH BAR ── */
.search-form { display: flex; align-items: center; position: relative; background: #000; border: var(--border-style); padding: 0.2rem 0.5rem; }
.search-form::before { content: ">"; color: var(--terminal-green); margin-right: 5px; font-weight: bold; }
.search-input { background: transparent; border: none; color: var(--terminal-green); font-family: var(--font-mono); font-size: 0.9rem; width: 140px; }
.search-input::placeholder { color: var(--terminal-dim); }
.search-input:focus { outline: none; width: 180px; }
.search-btn { display: none; } /* Hidden, press enter to search */

/* ── BREACH TOGGLE ── */
#theme-toggle { background: #000; border: var(--border-style); color: var(--terminal-green); font-family: var(--font-mono); font-size: 0.8rem; padding: 0.4rem 0.8rem; cursor: pointer; text-transform: uppercase; transition: all 0.2s; }
#theme-toggle:hover { background: var(--terminal-green); color: #000; }
[data-theme="breach"] #theme-toggle { border-color: var(--text-alert); color: var(--text-alert); }
[data-theme="breach"] #theme-toggle:hover { background: var(--text-alert); color: #000; }

/* ── CLI BUTTONS ── */
.btn-primary, .btn-secondary {
  display: inline-flex; align-items: center; justify-content: center;
  padding: 0.8rem 1.5rem; background: #000; color: var(--terminal-green);
  border: var(--border-style); font-family: var(--font-mono); font-size: 1rem; font-weight: bold;
  cursor: pointer; transition: all 0.1s; text-decoration: none;
}
.btn-primary::before { content: "./"; color: var(--text-muted); }
.btn-primary:hover { background: var(--terminal-green); color: #000 !important; box-shadow: 0 0 15px var(--terminal-glow); }
.btn-primary:hover::before { color: #000; }
.btn-secondary { border-style: dashed; }
.btn-secondary:hover { border-style: solid; background: var(--terminal-dark); }

/* ── HERO / TERMINAL WELCOME ── */
.hero { min-height: 70vh; padding: 4rem 2rem; position: relative; display: flex; flex-direction: column; justify-content: center; z-index: 10; max-width: 1000px; margin: 0 auto; }
.hero-prompt { color: var(--text-muted); margin-bottom: 1rem; }
.hero-title { font-size: clamp(2rem, 5vw, 4rem); font-weight: normal; line-height: 1.2; margin-bottom: 1.5rem; }
.hero-title span { color: #fff; background: var(--terminal-green); color: #000; padding: 0 10px; }
[data-theme="breach"] .hero-title span { background: var(--text-alert); }
.hero-desc { font-size: 1.1rem; color: var(--text-muted); margin-bottom: 3rem; max-width: 700px; border-left: 2px solid var(--terminal-dim); padding-left: 1rem; }
.hero-actions { display: flex; gap: 1rem; flex-wrap: wrap; }

/* ── TERMINAL CARDS ── */
.terminal-card {
  background: rgba(0, 5, 0, 0.85); border: var(--border-style);
  position: relative; padding: 2.5rem 2rem 2rem 2rem; margin-bottom: 2rem;
  box-shadow: 5px 5px 0px var(--terminal-dark); transition: transform 0.2s;
}
.terminal-card::before {
  content: "sysadmin@mr-ai-sec:~# " attr(data-title);
  position: absolute; top: 0; left: 0; width: 100%; background: var(--terminal-green); color: #000;
  padding: 3px 10px; font-size: 0.85rem; font-weight: bold; box-sizing: border-box;
}
[data-theme="breach"] .terminal-card { background: rgba(10, 0, 0, 0.85); box-shadow: 5px 5px 0px var(--terminal-dark); }
.terminal-card:hover { transform: translate(-2px, -2px); box-shadow: 7px 7px 0px var(--terminal-dim); }

/* ── GITHUB & YOUTUBE TERMINALS ── */
.stats-yt-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 2rem; margin-top: 3rem; }
.github-banner, .yt-banner { text-align: left; }
.github-banner .ascii-icon, .yt-banner .ascii-icon { font-size: 0.7rem; line-height: 1; color: var(--text-muted); margin-bottom: 1rem; white-space: pre; }

/* ── SECTIONS ── */
section.standard-section { padding: 4rem 2rem; max-width: 1200px; margin: 0 auto; width: 100%; position: relative; z-index: 10; }
.section-label { font-size: 0.9rem; color: var(--text-muted); margin-bottom: 0.5rem; }
.section-label::before { content: "cd "; }
.section-title { font-size: 2.5rem; margin-bottom: 2rem; border-bottom: 1px dashed var(--terminal-dim); padding-bottom: 0.5rem; display: inline-block; }
.section-title::after { content: " █"; animation: blinker 1s step-end infinite; }

/* ── ABOUT ── */
.about-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 2rem; }
.about-text { color: var(--terminal-green); line-height: 1.7; font-size: 1.05rem; }
.about-text p { margin-bottom: 1rem; }
.about-text p::before { content: "> "; color: var(--text-muted); }

.highlight-item { border-left: 2px solid var(--terminal-green); padding-left: 1rem; margin-bottom: 1.5rem; }
.highlight-info strong { display: block; color: #fff; font-size: 1.1rem; margin-bottom: 4px; }
.highlight-info span { color: var(--text-muted); font-size: 0.95rem; }

/* ── EXPERIENCE LOG ── */
.timeline { border-left: 1px dashed var(--terminal-green); padding-left: 2rem; margin-left: 10px; }
.timeline-item { position: relative; margin-bottom: 3rem; }
.timeline-item::before { content: "[+]"; position: absolute; left: -2.85rem; top: 0; background: #000; color: var(--terminal-green); font-weight: bold; padding: 2px; }
.timeline-period { font-size: 0.85rem; color: var(--text-muted); margin-bottom: 5px; }
.timeline-role { font-size: 1.3rem; color: #fff; margin-bottom: 5px; }
.timeline-org { color: var(--terminal-green); margin-bottom: 1rem; }
.timeline-points li { margin-bottom: 5px; color: var(--text-muted); }
.timeline-points li::before { content: "  |- "; color: var(--terminal-dim); }

/* ── PROJECTS / EXPLOITS ── */
.projects-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(300px, 1fr)); gap: 2rem; }
.project-card .project-date { color: var(--text-muted); font-size: 0.85rem; border-bottom: 1px solid var(--terminal-dark); padding-bottom: 5px; margin-bottom: 1rem; }
.project-name { font-size: 1.2rem; color: #fff; margin-bottom: 1rem; }
.project-name::before { content: "DIR: "; color: var(--text-muted); }
.project-desc { color: var(--terminal-green); line-height: 1.5; }

/* ── BLOG / LOGS ── */
.blog-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(300px, 1fr)); gap: 2rem; }
.blog-card .blog-date { color: var(--text-muted); font-size: 0.85rem; margin-bottom: 0.5rem; }
.blog-title { font-size: 1.3rem; margin-bottom: 1rem; }
.blog-title a { color: #fff; text-decoration: underline; text-decoration-style: dashed; text-underline-offset: 4px; }
.blog-title a:hover { color: var(--terminal-green); text-decoration-style: solid; background: var(--terminal-dark); }
.blog-snippet { color: var(--text-muted); line-height: 1.5; margin-bottom: 1.5rem; flex-grow: 1; }
.read-more { font-weight: bold; background: var(--terminal-dark); padding: 5px 10px; border: var(--border-style); color: var(--terminal-green) !important; }
.read-more:hover { background: var(--terminal-green); color: #000 !important; }

/* ── FULL POST VIEW ── */
.post-container { @extend .terminal-card; max-width: 900px; margin: 2rem auto; }
.post-header { border-bottom: 1px dashed var(--terminal-dim); padding-bottom: 2rem; margin-bottom: 2rem; text-align: left; }
.post-header h1 { font-size: clamp(2rem, 4vw, 3rem); color: #fff; margin: 1rem 0; }
.post-meta-tags { display: flex; gap: 1rem; color: var(--text-muted); font-size: 0.9rem; }
.post-tag { background: #000; border: 1px solid var(--text-muted); padding: 2px 8px; }

.post-hero-image { border: var(--border-style); padding: 5px; background: #000; margin-bottom: 2rem; filter: grayscale(100%) contrast(1.2); transition: filter 0.3s; }
.post-hero-image:hover { filter: grayscale(0%); }
.post-hero-image img { width: 100% !important; height: auto !important; display: block; }
.post-body .separator, .post-body img { display: none !important; }

.post-body { color: var(--terminal-green); line-height: 1.7; }
.post-body h2, .post-body h3 { color: #fff; margin: 2.5rem 0 1rem; border-left: 4px solid var(--terminal-green); padding-left: 10px; }
.post-body p { margin-bottom: 1.5rem; }
.post-body a { color: #fff; border-bottom: 1px dashed #fff; background: var(--terminal-dark); padding: 0 4px; }
.post-body a:hover { background: #fff; color: #000; }
.post-body blockquote { border: 1px solid var(--terminal-dim); border-left: 4px solid var(--terminal-green); padding: 1rem; margin: 2rem 0; background: rgba(0,255,65,0.05); font-style: italic; }
.post-body pre { background: #000; border: var(--border-style); padding: 1rem; overflow-x: auto; margin: 2rem 0; color: #fff; }

/* ── SKILLS ── */
.skills-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(250px, 1fr)); gap: 1.5rem; }
.skill-category .skill-cat-title { color: #fff; border-bottom: 1px solid var(--terminal-dim); padding-bottom: 5px; margin-bottom: 1rem; }
.skill-tags { display: flex; flex-wrap: wrap; gap: 8px; }
.skill-tag { background: #000; border: 1px solid var(--terminal-dim); padding: 4px 8px; font-size: 0.85rem; color: var(--terminal-green); }
.skill-tag:hover { background: var(--terminal-green); color: #000; border-color: var(--terminal-green); }

.certs-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 1.5rem; margin-top: 2rem; }
.cert-issuer { color: var(--text-muted); font-size: 0.8rem; margin-bottom: 5px; }
.cert-name { color: #fff; margin-bottom: 5px; }

/* ── CONTACT ── */
.contact-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 2rem; }
.contact-item { display: flex; align-items: center; gap: 1rem; margin-bottom: 1.5rem; border: 1px dashed transparent; padding: 10px; }
.contact-item:hover { border-color: var(--terminal-green); background: var(--terminal-dark); }
.contact-label { color: var(--text-muted); font-size: 0.85rem; }
.contact-value { color: #fff; font-size: 1.1rem; }
.contact-card { background: #000; border: var(--border-style); padding: 2rem; }

/* ── AD BLOCKS ── */
.ad-sponsor-block {
  margin: 2rem 0; padding: 1rem; border: 1px dashed var(--text-alert); background: #000; text-align: center; position: relative;
}
.ad-sponsor-label { position: absolute; top: -10px; left: 10px; background: #000; color: var(--text-alert); padding: 0 5px; font-size: 0.8rem; }

/* ── FOOTER ── */
.site-footer { border-top: var(--border-style); background: #000; padding: 2rem; margin-top: 4rem; position: relative; z-index: 10; text-align: center; }
.footer-bottom { max-width: 1200px; margin: 0 auto; display: flex; justify-content: space-between; align-items: center; flex-wrap: wrap; gap: 1rem; }
.footer-bottom p { color: var(--text-muted); font-size: 0.9rem; margin: 0; }
.inline-legal-links { display: flex; gap: 1.5rem; }
.inline-legal-links a { color: var(--terminal-green); font-size: 0.85rem; }

/* ── MOBILE ── */
@media (max-width: 768px) {
  .stats-yt-grid, .about-grid, .contact-grid { grid-template-columns: 1fr; }
  .hamburger { display: block; }
  .nav-right {
    display: none; position: absolute; top: 100%; left: 0; width: 100%;
    background: #000; border-bottom: var(--border-style);
    flex-direction: column; padding: 1rem; gap: 1rem; z-index: 100;
  }
  .nav-right.active { display: flex; }
  .nav-links { flex-direction: column; width: 100%; gap: 1rem; align-items: flex-start; }
  .search-form { width: 100%; margin-bottom: 1rem; }
  .dropdown-content { position: static; min-width: 100%; border: none; padding-left: 1rem; }
  .footer-bottom { flex-direction: column; justify-content: center; }
}

/* ── SCROLLBAR ── */
::-webkit-scrollbar { width: 10px; }
::-webkit-scrollbar-track { background: #000; border-left: 1px solid var(--terminal-dark); }
::-webkit-scrollbar-thumb { background: var(--terminal-green); }
[data-theme="breach"] ::-webkit-scrollbar-thumb { background: var(--text-alert); }

body.script:
//
  /* ── HTML5 CANVAS MATRIX RAIN ── */
  const canvas = document.getElementById('matrixCanvas');
  const ctx = canvas.getContext('2d');

  function resizeCanvas() {
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
  }
  window.addEventListener('resize', resizeCanvas);
  resizeCanvas();

  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789$+-*/=%""\'#&_(),.;:?!\\|{}<>[]^~'.split('');
  const fontSize = 16;
  let columns = canvas.width / fontSize;
  let drops = [];

  for (let x = 0; x < columns; x++) { drops[x] = 1; }

  // Check current theme for rain color
  function getRainColor() {
      if (document.body.getAttribute('data-theme') === 'breach') {
          return '#ff003c'; // Red rain
      }
      return '#00ff41'; // Green rain
  }

  function drawMatrix() {
    ctx.fillStyle = 'rgba(0, 0, 0, 0.05)';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    ctx.fillStyle = getRainColor();
    ctx.font = fontSize + 'px "Share Tech Mono", monospace';

    for (let i = 0; i < drops.length; i++) {
      const text = chars[Math.floor(Math.random() * chars.length)];
      ctx.fillText(text, i * fontSize, drops[i] * fontSize);

      if (drops[i] * fontSize > canvas.height && Math.random() > 0.975) {
        drops[i] = 0;
      }
      drops[i]++;
    }
  }
  setInterval(drawMatrix, 35);

  /* ── BREACH (THEME) TOGGLE ── */
  function toggleTheme() {
    const body = document.body;
    const current = body.getAttribute('data-theme');
    body.setAttribute('data-theme', current === 'breach' ? '' : 'breach');
    localStorage.setItem('theme', body.getAttribute('data-theme'));

    // Reset canvas to clear trailing colors instantly
    ctx.fillStyle = 'black';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
  }

  (function() {
    const saved = localStorage.getItem('theme');
    if (saved === 'breach') document.body.setAttribute('data-theme', 'breach');
  })();

  /* ── MOBILE MENU ── */
  function toggleMenu() {
    const navMenu = document.getElementById('nav-menu');
    navMenu.classList.toggle('active');
  }

  /* ── SCROLL REVEAL ── */
  const observer = new IntersectionObserver((entries) => {
    entries.forEach(e => {
      if (e.isIntersecting) {
        e.target.classList.add('visible');
        observer.unobserve(e.target);
      }
    });
  }, { threshold: 0.1, rootMargin: '0px 0px -40px 0px' });

  const revealElements = document.querySelectorAll('.reveal');
  if(revealElements.length > 0) {
      revealElements.forEach(el => observer.observe(el));
  }

  /* ── CLEANUP LEFTOVER SPACES ── */
  document.addEventListener("DOMContentLoaded", function() {
    if (document.querySelector('.post-container')) {
      const postBodies = document.querySelectorAll('.post-body');
      postBodies.forEach(body => {
        let node = body.firstChild;
        while (node) {
          let next = node.nextSibling;
          if (node.nodeName === 'BR' || 
             (node.nodeType === 3 && node.textContent.trim() === '') ||
             (node.classList && node.classList.contains('separator')) ||
             (node.nodeName === 'P' && node.innerHTML.trim() === '')) {
            node.remove();
          } else {
            break;
          }
          node = next;
        }
      });
    }
  });
//
